import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.Dn7Y7LSn.js";const u=JSON.parse('{"title":"What is ilias?","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guides/what-is-ilias.md","filePath":"guides/what-is-ilias.md"}'),n={name:"guides/what-is-ilias.md"};function s(r,e,c,l,d,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="what-is-ilias" tabindex="-1">What is ilias? <a class="header-anchor" href="#what-is-ilias" aria-label="Permalink to &quot;What is ilias?&quot;">​</a></h1><p>ilias is a modern, completion-based asynchronous runtime. It aims to provide developers with a smooth development experience and performance similar to Tokio, while also ensuring interoperability with other asynchronous ecosystems.</p><h2 id="why-reinvent-the-wheel" tabindex="-1">Why Reinvent the Wheel? <a class="header-anchor" href="#why-reinvent-the-wheel" aria-label="Permalink to &quot;Why Reinvent the Wheel?&quot;">​</a></h2><p>Previously, when writing network-related code for my Qt applications, I fell into callback hell.</p><p>Every time I needed to handle a network request, I had to write a callback function and then connect it to a Qt signal. I found that as the logic became more complex, this callback hell became difficult to maintain, and the lifecycle was almost uncontrollable, requiring the use of <code>shared_ptr</code>. So, I turned my attention to existing coroutine libraries.</p><p><code>cppcoro</code> is a pioneer of C++20 stackless coroutines, but it hasn&#39;t been maintained for a long time, and its networking part only supports Windows.</p><p><code>asio</code> is a long-standing asynchronous library, but its coroutine cancellation forces a reliance on exceptions. I prefer not to use exceptions for cancellation because an exception crossing an await point requires a rethrow + catch, which I find to be rather inefficient.</p><p><code>folly</code> and <code>seastar</code> are advanced, but they are heavyweight.</p><p>So I turned my attention to Rust and saw Tokio. I found its API design to be quite good, with a rich ecosystem. However, in practice, I found that its cancellation and a few other aspects didn&#39;t quite suit my taste; for example, the default <code>spawn</code> requires <code>Send + Sync</code>. Then, I came across <code>std::execution</code> and discovered that its cancellation design is excellent and safe, featuring structured concurrency. So, I decided to act on it. After referencing the concepts of Tokio and <code>stdexec</code>, ilias was born. I want to make asynchronous programming painless for myself, to be able to write fast, safe programs in C++ that are compatible with existing ecosystems.</p><h2 id="design-philosophy" tabindex="-1">Design Philosophy <a class="header-anchor" href="#design-philosophy" aria-label="Permalink to &quot;Design Philosophy&quot;">​</a></h2><ul><li><strong>One scheduler per thread:</strong> The simplest model, easy to integrate into other asynchronous ecosystems, and inherently lock-free.</li><li><strong>Completion-based + Asynchronous Cancellation:</strong> Cancellation is not a direct <code>Drop</code>. It sends a cancellation signal and then asynchronously waits for the underlying cancellation to complete.</li></ul>',11)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
